17	// RBTDRK — gauntlet canonical-establish fixture (§2 of release qualification)
18	//
19	// Establishes long-lived canonical state the gauntlet's downstream fixtures
20	// inherit:
21	//   1. depot_levy        — install canonical RBRR prefixes; levy a fresh canest depot
22	//   2. governor_mantle   — mantle governor against the canonical depot
23	//   3. retriever_invest  — invest a canonical retriever SA + access-probe
24	//   4. director_invest   — invest a canonical director SA + access-probe
25	//
26	// Disposition: StateProgressing. Each case carries a precondition probe via
27	// rbtdrb_Probe so a-la-carte single-case rerun fails cleanly when an earlier
28	// case's state is absent. Tabtarget invocations are responsible for waiting
29	// out their own propagation (no separate iam-propagation-wait case).
30	
31	use std::path::{Path, PathBuf};
32	use std::process::Command;
33	
34	use crate::case;
35	use crate::rbtdrb_probe::{rbtdrb_assert, rbtdrb_Probe};
36	use crate::rbtdrc_crucible::rbtdrc_with_ctx;
37	use crate::rbtdre_engine::{rbtdre_Case, rbtdre_Disposition, rbtdre_Fixture, rbtdre_Verdict};
38	use crate::rbtdri_invocation::{
39	    rbtdri_invoke_global, rbtdri_invoke_imprint, rbtdri_read_burv_fact, rbtdri_Context,
40	    rbtdri_InvokeResult, RBTDRI_BURV_OUTPUT_SUBDIR,
41	};
42	use crate::rbtdrm_manifest::{
43	    RBTDRM_COLOPHON_ACCESS_PROBE, RBTDRM_COLOPHON_DEPOT_LEVY, RBTDRM_COLOPHON_DEPOT_LIST,
44	    RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR, RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
45	    RBTDRM_COLOPHON_GOV_MANTLE, RBTDRM_FIXTURE_CANONICAL_ESTABLISH,
46	};
47	
48	// ── Canonical-fixture identities ─────────────────────────────
49	
50	/// Canonical RBRR prefix bases installed by case 1. Distinct from pristine's
51	/// throwaway prefix bases (prlc/prlr); per-station tincture from BURS is
52	/// composed in at runtime so parallel-station runs land in disjoint cloud
53	/// names. Case 2's probe detects canonical state by reading the moniker's
54	/// family stem (also tinctured) from rbrr.env.
55	pub(crate) const RBTDRK_CANONICAL_CLOUD_BASE: &str = "canc";
56	pub(crate) const RBTDRK_CANONICAL_RUNTIME_BASE: &str = "canr";
57	
58	/// Family-stem base for canonical depots; six-digit auto-increment suffix per
59	/// run. Depots persist post-success for operator inspection; reruns pick the
60	/// next free suffix by walking depot_list output. Per-station tincture is
61	/// composed in at runtime so each station's monikers fact-file-walk against
62	/// a disjoint family stem. Era-bumped past the prior `canest` family to
63	/// side-step pending-delete projectId reservations from burned-bridges
64	/// teardown.
65	pub(crate) const RBTDRK_FAMILY_STEM_BASE: &str = "canest2";
66	
67	/// Static identities for the canonical SA cycle. Stable across runs because
68	/// each run uses a fresh canest depot project.
69	const RBTDRK_IDENTITY_RETRIEVER: &str = "canest-ret";
70	const RBTDRK_IDENTITY_DIRECTOR: &str = "canest-dir";
71	
72	const RBTDRK_FAMILY_NUMERIC_FLOOR: u32 = 100000;
73	const RBTDRK_FAMILY_NUMERIC_WIDTH: usize = 6;
74	
75	const RBTDRK_FACT_EXT_DEPOT: &str = "depot";
76	const RBTDRK_FACT_EXT_DEPOT_PROJECT: &str = "depot-project";
77	const RBTDRK_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
78	
79	const RBTDRK_FIELD_RBRR_CLOUD_PREFIX: &str = "RBRR_CLOUD_PREFIX";
80	const RBTDRK_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
81	const RBTDRK_FIELD_RBRR_DEPOT_MONIKER: &str = "RBRR_DEPOT_MONIKER";
82	const RBTDRK_FIELD_RBRR_SECRETS_DIR: &str = "RBRR_SECRETS_DIR";
83	
84	const RBTDRK_RBRR_FILE: &str = ".rbk/rbrr.env";
85	const RBTDRK_RBRA_FILE: &str = "rbra.env";
86	
87	/// BURS station-file env var (exported by bul_launcher.sh) — absolute path
88	/// to the developer's burs.env. Source for BURS_TINCTURE.
89	const RBTDRK_ENV_STATION_FILE: &str = "BURD_STATION_FILE";
90	
91	/// Read BURS_TINCTURE from the station file resolved via BURD_STATION_FILE.
92	/// BURS validation upstream (zburs_enforce) guarantees the value is 1-3 chars
93	/// of lowercase alphanumeric starting with a letter.
94	pub(crate) fn rbtdrk_burs_tincture() -> Result<String, String> {
95	    let path_str = std::env::var(RBTDRK_ENV_STATION_FILE)
96	        .map_err(|_| format!("{} not set in environment", RBTDRK_ENV_STATION_FILE))?;
97	    let path = PathBuf::from(&path_str);
98	    rbtdrk_read_env_value(&path, "BURS_TINCTURE")
99	        .ok_or_else(|| format!("BURS_TINCTURE not in {}", path.display()))
100	}
101	
102	/// Compose canonical RBRR_CLOUD_PREFIX with the given tincture.
103	pub(crate) fn rbtdrk_canonical_cloud_prefix(tincture: &str) -> String {
104	    format!("{}{}-", RBTDRK_CANONICAL_CLOUD_BASE, tincture)
105	}
106	
107	/// Compose canonical RBRR_RUNTIME_PREFIX with the given tincture.
108	pub(crate) fn rbtdrk_canonical_runtime_prefix(tincture: &str) -> String {
109	    format!("{}{}-", RBTDRK_CANONICAL_RUNTIME_BASE, tincture)
110	}
111	
112	/// Compose canonical family stem with the given tincture.
113	pub(crate) fn rbtdrk_family_stem(tincture: &str) -> String {
114	    format!("{}{}", RBTDRK_FAMILY_STEM_BASE, tincture)
115	}
