117	// ── Helpers ──────────────────────────────────────────────────
118	
119	/// Read an env-file value or None if absent. Mirrors pristine's helper —
120	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
121	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
122	    let content = std::fs::read_to_string(path).ok()?;
123	    let prefix = format!("{}=", key);
124	    for line in content.lines() {
125	        let trimmed = line.trim_start();
126	        if trimmed.starts_with('#') {
127	            continue;
128	        }
129	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
130	            return Some(rest.to_string());
131	        }
132	    }
133	    None
134	}
135	
136	fn rbtdrk_resolve(root: &Path, raw: &str) -> PathBuf {
137	    if Path::new(raw).is_absolute() {
138	        PathBuf::from(raw)
139	    } else {
140	        root.join(raw)
141	    }
142	}
143	
144	fn rbtdrk_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
145	    let mut result: String = content
146	        .lines()
147	        .map(|line| {
148	            for (key, value) in pairs {
149	                let assign = format!("{}=", key);
150	                if line.starts_with(&assign) {
151	                    return format!("{}{}", assign, value);
152	                }
153	            }
154	            line.to_string()
155	        })
156	        .collect::<Vec<_>>()
157	        .join("\n");
158	    if content.ends_with('\n') {
159	        result.push('\n');
160	    }
161	    result
162	}
163	
164	fn rbtdrk_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
165	    let add = Command::new("git")
166	        .args(["add", file])
167	        .current_dir(root)
168	        .output()
169	        .map_err(|e| format!("rbtdrk: git add invocation failed: {}", e))?;
170	    if !add.status.success() {
171	        return Err(format!(
172	            "rbtdrk: git add failed (exit {}): {}",
173	            add.status.code().unwrap_or(-1),
174	            String::from_utf8_lossy(&add.stderr).trim()
175	        ));
176	    }
177	    let commit = Command::new("git")
178	        .args(["commit", "-m", message])
179	        .current_dir(root)
180	        .output()
181	        .map_err(|e| format!("rbtdrk: git commit invocation failed: {}", e))?;
182	    if !commit.status.success() {
183	        return Err(format!(
184	            "rbtdrk: git commit failed (exit {}): {}",
185	            commit.status.code().unwrap_or(-1),
186	            String::from_utf8_lossy(&commit.stderr).trim()
187	        ));
188	    }
189	    Ok(())
190	}
191	
192	/// Resolve canonical RBRA path for a role: <RBRR_SECRETS_DIR>/<role>/rbra.env.
193	pub(crate) fn rbtdrk_canonical_rbra(root: &Path, role: &str) -> Result<PathBuf, String> {
194	    let rbrr = root.join(RBTDRK_RBRR_FILE);
195	    let secrets_dir = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_SECRETS_DIR)
196	        .ok_or_else(|| format!("RBRR_SECRETS_DIR missing from {}", rbrr.display()))?;
197	    if secrets_dir.is_empty() {
198	        return Err(format!("RBRR_SECRETS_DIR is blank in {}", rbrr.display()));
199	    }
200	    Ok(rbtdrk_resolve(root, &secrets_dir)
201	        .join(role)
202	        .join(RBTDRK_RBRA_FILE))
203	}
204	
205	// ── Canonical-prefix install (case 1) ───────────────────────
206	
207	/// Idempotently install canc-/canr- prefixes into rbrr.env. Returns Ok
208	/// without committing when prefixes already match the canonical markers;
209	/// otherwise rewrites both lines and commits.
210	pub(crate) fn rbtdrk_install_canonical_prefixes(root: &Path) -> Result<(), String> {
211	    let rbrr = root.join(RBTDRK_RBRR_FILE);
212	    let tincture = rbtdrk_burs_tincture()?;
213	    let cloud_target = rbtdrk_canonical_cloud_prefix(&tincture);
214	    let runtime_target = rbtdrk_canonical_runtime_prefix(&tincture);
215	
216	    let cloud = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
217	    let runtime =
218	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
219	    if cloud == cloud_target && runtime == runtime_target {
220	        return Ok(());
221	    }
222	    let content = std::fs::read_to_string(&rbrr)
223	        .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
224	    let new_content = rbtdrk_replace_env_fields(
225	        &content,
226	        &[
227	            (RBTDRK_FIELD_RBRR_CLOUD_PREFIX, cloud_target.as_str()),
228	            (RBTDRK_FIELD_RBRR_RUNTIME_PREFIX, runtime_target.as_str()),
229	        ],
230	    );
231	    std::fs::write(&rbrr, &new_content)
232	        .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
233	    let commit_msg = format!(
234	        "canonical-establish fixture: install canonical RBRR prefixes ({}/{})",
235	        cloud_target, runtime_target
236	    );
237	    rbtdrk_git_add_and_commit(root, RBTDRK_RBRR_FILE, &commit_msg)
238	}
239	
240	fn rbtdrk_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
241	    let rbrr = root.join(RBTDRK_RBRR_FILE);
242	    let content = std::fs::read_to_string(&rbrr)
243	        .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
244	    let new_content =
245	        rbtdrk_replace_env_fields(&content, &[(RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker)]);
246	    std::fs::write(&rbrr, &new_content)
247	        .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
248	    let commit_msg = format!(
249	        "canonical-establish fixture: set {}={}",
250	        RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker
251	    );
252	    rbtdrk_git_add_and_commit(root, RBTDRK_RBRR_FILE, &commit_msg)
253	}
254	
255	/// Compose depot project_id from kindled regime values: <CLOUD>d-<moniker>.
256	fn rbtdrk_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
257	    let rbrr = root.join(RBTDRK_RBRR_FILE);
258	    let cloud_prefix = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_CLOUD_PREFIX)
259	        .ok_or_else(|| format!("RBRR_CLOUD_PREFIX missing from {}", rbrr.display()))?;
260	    Ok(format!("{}d-{}", cloud_prefix, moniker))
261	}
262	
263	/// Pick the next free moniker for `family_stem` by walking the depot_list
264	/// invocation's BURV output dir for `<family>NNNNNN.depot` files. Returns
265	/// `<family>RBTDRK_FAMILY_NUMERIC_FLOOR` when no matching files exist.
266	///
267	/// Caller contract: `list_result` MUST be from a freshly-invoked depot_list
268	/// that ran in the current process. The fact-file scan IS the collision
269	/// check — stale state means picking a colliding moniker. Do not reuse a
270	/// `list_result` across cases or pass an operator-cached value.
271	fn rbtdrk_pick_next_moniker(
272	    list_result: &rbtdri_InvokeResult,
273	    family_stem: &str,
274	) -> Result<String, String> {
275	    let dir = list_result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
276	    let entries = match std::fs::read_dir(&dir) {
277	        Ok(e) => e,
278	        Err(_) => {
279	            return Ok(format!("{}{}", family_stem, RBTDRK_FAMILY_NUMERIC_FLOOR));
280	        }
281	    };
282	    let suffix_ext = format!(".{}", RBTDRK_FACT_EXT_DEPOT);
283	    let mut max_suffix: Option<u32> = None;
284	    for entry in entries.flatten() {
285	        let name = match entry.file_name().into_string() {
286	            Ok(n) => n,
287	            Err(_) => continue,
288	        };
289	        let stem = match name.strip_suffix(&suffix_ext) {
290	            Some(s) => s,
291	            None => continue,
292	        };
293	        let numeric = match stem.strip_prefix(family_stem) {
294	            Some(s) => s,
295	            None => continue,
296	        };
297	        if numeric.len() != RBTDRK_FAMILY_NUMERIC_WIDTH {
298	            continue;
299	        }
300	        let parsed: u32 = match numeric.parse() {
301	            Ok(n) => n,
302	            Err(_) => continue,
303	        };
304	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
305	    }
306	    let next = match max_suffix {
307	        Some(m) => m + 1,
308	        None => RBTDRK_FAMILY_NUMERIC_FLOOR,
309	    };
310	    Ok(format!("{}{}", family_stem, next))
311	}
312	
313	fn rbtdrk_invoke_logged(
314	    ctx: &mut rbtdri_Context,
315	    colophon: &str,
316	    args: &[&str],
317	    extra_env: &[(&str, &str)],
318	    dir: &Path,
319	    label: &str,
320	) -> Result<rbtdri_InvokeResult, String> {
321	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
322	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
323	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
324	    Ok(result)
325	}
326	
327	// ── Probes ───────────────────────────────────────────────────
328	
329	/// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
330	/// have no context, so they read the project root from current_dir() — theurge
331	/// always launches from the project root.
332	fn rbtdrk_probe_root() -> Result<PathBuf, String> {
333	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
334	}
335	
336	/// Case 1 probe: rbrr.env exists. Sanity precondition — canonical-establish
337	/// presumes the regime has been initialized at least to the marshal-zero
338	/// blank-template shape.
339	fn rbtdrk_probe_rbrr_present() -> Result<(), String> {
340	    let root = rbtdrk_probe_root()?;
341	    let rbrr = root.join(RBTDRK_RBRR_FILE);
342	    if !rbrr.exists() {
343	        return Err(format!("rbrr.env not found at {}", rbrr.display()));
344	    }
345	    Ok(())
346	}
347	
348	/// Case 2 probe: canonical depot moniker installed in rbrr.env. Established
349	/// by case 1; absence means depot-levy didn't run or rbrr.env was rewritten.
350	fn rbtdrk_probe_canonical_moniker() -> Result<(), String> {
351	    let root = rbtdrk_probe_root()?;
352	    let rbrr = root.join(RBTDRK_RBRR_FILE);
353	    let tincture = rbtdrk_burs_tincture()?;
354	    let family_stem = rbtdrk_family_stem(&tincture);
355	    let moniker =
356	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_DEPOT_MONIKER).unwrap_or_default();
357	    if !moniker.starts_with(&family_stem) {
358	        return Err(format!(
359	            "{}={:?} does not begin with '{}' — canonical depot moniker not installed",
360	            RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker, family_stem
361	        ));
362	    }
363	    Ok(())
364	}
365	
366	/// Cases 3 and 4 probe: governor RBRA file present at the canonical path.
367	/// Established by case 2's mantle + canonical-copy step.
368	fn rbtdrk_probe_governor_rbra() -> Result<(), String> {
369	    let root = rbtdrk_probe_root()?;
370	    let path = rbtdrk_canonical_rbra(&root, "governor")?;
371	    if !path.exists() {
372	        return Err(format!("governor RBRA absent at {}", path.display()));
373	    }
374	    Ok(())
375	}
376	
377	// ── Cases ────────────────────────────────────────────────────
378	
379	/// Case 1 — canonical depot levy. Installs canc-/canr- prefixes, picks a
380	/// fresh canest moniker, levies the depot, cross-checks project_id from
381	/// fact-file against the RBDC compose derivation.
382	fn rbtdrk_depot_levy(dir: &Path) -> rbtdre_Verdict {
383	    let probe = rbtdrb_Probe {
384	        name: "rbrr.env present",
385	        check: rbtdrk_probe_rbrr_present,
386	        remediation: "ensure regime is initialized — rerun pristine-lifecycle if needed",
387	    };
388	    if let Err(v) = rbtdrb_assert(&probe) {
389	        return v;
390	    }
391	    rbtdrc_with_ctx(|ctx| rbtdrk_depot_levy_impl(ctx, dir))
392	}
393	
394	fn rbtdrk_depot_levy_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
395	    let root = ctx.project_root().to_path_buf();
396	
397	    if let Err(e) = rbtdrk_install_canonical_prefixes(&root) {
398	        return rbtdre_Verdict::Fail(format!("install canonical prefixes: {}", e));
399	    }
400	
401	    let list_pre = match rbtdrk_invoke_logged(
402	        ctx,
403	        RBTDRM_COLOPHON_DEPOT_LIST,
404	        &[],
405	        &[],
406	        dir,
407	        "list-pre",
408	    ) {
409	        Ok(r) => r,
410	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy): {}", e)),
411	    };
412	    if list_pre.exit_code != 0 {
413	        return rbtdre_Verdict::Fail(format!(
414	            "depot list (pre-levy) exit {}\n{}",
415	            list_pre.exit_code, list_pre.stderr
416	        ));
417	    }
418	
419	    let tincture = match rbtdrk_burs_tincture() {
420	        Ok(t) => t,
421	        Err(e) => return rbtdre_Verdict::Fail(format!("read BURS_TINCTURE: {}", e)),
422	    };
423	    let family_stem = rbtdrk_family_stem(&tincture);
424	    let moniker = match rbtdrk_pick_next_moniker(&list_pre, &family_stem) {
425	        Ok(m) => m,
426	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
427	    };
428	    if let Err(e) = rbtdrk_install_depot_moniker(&root, &moniker) {
429	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
430	    }
431	
432	    let levy = match rbtdrk_invoke_logged(
433	        ctx,
434	        RBTDRM_COLOPHON_DEPOT_LEVY,
435	        &[],
436	        &[],
437	        dir,
438	        "levy",
439	    ) {
440	        Ok(r) => r,
441	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
442	    };
443	    if levy.exit_code != 0 {
444	        return rbtdre_Verdict::Fail(format!(
445	            "depot levy exit {}\n{}",
446	            levy.exit_code, levy.stderr
447	        ));
448	    }
449	
450	    let list_present = match rbtdrk_invoke_logged(
451	        ctx,
452	        RBTDRM_COLOPHON_DEPOT_LIST,
453	        &[],
454	        &[],
455	        dir,
456	        "list-present",
457	    ) {
458	        Ok(r) => r,
459	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
460	    };
461	    if list_present.exit_code != 0 {
462	        return rbtdre_Verdict::Fail(format!(
463	            "depot list (after levy) exit {}\n{}",
464	            list_present.exit_code, list_present.stderr
465	        ));
466	    }
467	
468	    let fact_path = list_present
469	        .burv_output
470	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
471	        .join(format!("{}.{}", moniker, RBTDRK_FACT_EXT_DEPOT_PROJECT));
472	    let fact_project_id = match std::fs::read_to_string(&fact_path) {
473	        Ok(s) => s.trim().to_string(),
474	        Err(e) => {
475	            return rbtdre_Verdict::Fail(format!(
476	                "read depot-project fact '{}': {}",
477	                fact_path.display(),
478	                e
479	            ))
480	        }
481	    };
482	    if fact_project_id.is_empty() {
483	        return rbtdre_Verdict::Fail(format!(
484	            "depot-project fact is empty: {}",
485	            fact_path.display()
486	        ));
487	    }
488	    let _ = std::fs::write(dir.join("project-id.txt"), &fact_project_id);
489	
490	    let composed = match rbtdrk_compose_project_id(&root, &moniker) {
491	        Ok(p) => p,
492	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
493	    };
494	    if composed != fact_project_id {
495	        return rbtdre_Verdict::Fail(format!(
496	            "project_id mismatch: RBDC compose='{}' vs depot-list fact='{}' \
497	             (RBDC kindle derivation diverged from payor creation)",
498	            composed, fact_project_id
499	        ));
500	    }
501	    rbtdre_Verdict::Pass
502	}
503	
504	/// Case 2 — governor mantle. Mantles governor against the canonical depot,
505	/// reads the SA email fact, copies governor RBRA from BURV output to the
506	/// canonical path under RBRR_SECRETS_DIR.
507	fn rbtdrk_governor_mantle(dir: &Path) -> rbtdre_Verdict {
508	    let probe = rbtdrb_Probe {
509	        name: "canonical depot moniker installed",
510	        check: rbtdrk_probe_canonical_moniker,
511	        remediation: "rerun rbtdrk_depot_levy or the full canonical-establish fixture",
512	    };
513	    if let Err(v) = rbtdrb_assert(&probe) {
514	        return v;
515	    }
516	    rbtdrc_with_ctx(|ctx| rbtdrk_governor_mantle_impl(ctx, dir))
517	}
518	
519	fn rbtdrk_governor_mantle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
520	    let root = ctx.project_root().to_path_buf();
521	
522	    let assay = match rbtdrk_canonical_rbra(&root, "assay") {
523	        Ok(p) => p,
524	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
525	    };
526	
527	    let mantle = match rbtdrk_invoke_logged(
528	        ctx,
529	        RBTDRM_COLOPHON_GOV_MANTLE,
530	        &[],
531	        &[],
532	        dir,
533	        "mantle",
534	    ) {
535	        Ok(r) => r,
536	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
537	    };
538	    if mantle.exit_code != 0 {
539	        return rbtdre_Verdict::Fail(format!(
540	            "governor mantle exit {}\n{}",
541	            mantle.exit_code, mantle.stderr
542	        ));
543	    }
544	
545	    let email = match rbtdri_read_burv_fact(&mantle, RBTDRK_FACT_GOVERNOR_SA_EMAIL) {
546	        Ok(s) => s,
547	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
548	    };
549	    let _ = std::fs::write(dir.join("governor-sa-email.txt"), &email);
550	
551	    if !assay.exists() {
552	        return rbtdre_Verdict::Fail(format!(
553	            "assay RBRA absent after governor mantle: {}",
554	            assay.display()
555	        ));
556	    }
557	
558	    let canonical = match rbtdrk_canonical_rbra(&root, "governor") {
559	        Ok(p) => p,
560	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical governor RBRA path: {}", e)),
561	    };
562	    if let Some(parent) = canonical.parent() {
563	        if let Err(e) = std::fs::create_dir_all(parent) {
564	            return rbtdre_Verdict::Fail(format!(
565	                "create governor RBRA dir {}: {}",
566	                parent.display(),
567	                e
568	            ));
569	        }
570	    }
571	    if let Err(e) = std::fs::copy(&assay, &canonical) {
572	        return rbtdre_Verdict::Fail(format!(
573	            "copy assay RBRA → governor canonical {}: {}",
574	            canonical.display(),
575	            e
576	        ));
577	    }
578	    rbtdre_Verdict::Pass
579	}
580	
581	/// Case 3 — retriever invest + access-probe. The access-probe doubles as the
582	/// IAM-propagation gate: the invest tabtarget is responsible for waiting on
583	/// propagation before exiting (or the probe iterates internally). No separate
584	/// propagation-wait case.
585	fn rbtdrk_retriever_invest(dir: &Path) -> rbtdre_Verdict {
586	    let probe = rbtdrb_Probe {
587	        name: "governor RBRA present",
588	        check: rbtdrk_probe_governor_rbra,
589	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
590	    };
591	    if let Err(v) = rbtdrb_assert(&probe) {
592	        return v;
593	    }
594	    rbtdrc_with_ctx(|ctx| {
595	        rbtdrk_role_invest_impl(
596	            ctx,
597	            dir,
598	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
599	            RBTDRK_IDENTITY_RETRIEVER,
600	            "retriever",
601	        )
602	    })
603	}
604	
605	/// Case 4 — director invest + access-probe.
606	fn rbtdrk_director_invest(dir: &Path) -> rbtdre_Verdict {
607	    let probe = rbtdrb_Probe {
608	        name: "governor RBRA present",
609	        check: rbtdrk_probe_governor_rbra,
610	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
611	    };
612	    if let Err(v) = rbtdrb_assert(&probe) {
613	        return v;
614	    }
615	    rbtdrc_with_ctx(|ctx| {
616	        rbtdrk_role_invest_impl(
617	            ctx,
618	            dir,
619	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
620	            RBTDRK_IDENTITY_DIRECTOR,
621	            "director",
622	        )
623	    })
624	}
625	
626	/// Shared invest body for retriever and director: invest → assert assay
627	/// dropped by the invest tabtarget → copy to canonical role path → access-probe.
628	fn rbtdrk_role_invest_impl(
629	    ctx: &mut rbtdri_Context,
630	    dir: &Path,
631	    invest_colophon: &str,
632	    identity: &str,
633	    role: &str,
634	) -> rbtdre_Verdict {
635	    let root = ctx.project_root().to_path_buf();
636	
637	    let assay = match rbtdrk_canonical_rbra(&root, "assay") {
638	        Ok(p) => p,
639	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
640	    };
641	
642	    let label_invest = format!("invest-{}", role);
643	    let invest = match rbtdrk_invoke_logged(
644	        ctx,
645	        invest_colophon,
646	        &[identity],
647	        &[],
648	        dir,
649	        &label_invest,
650	    ) {
651	        Ok(r) => r,
652	        Err(e) => return rbtdre_Verdict::Fail(format!("invest {}: {}", role, e)),
653	    };
654	    if invest.exit_code != 0 {
655	        return rbtdre_Verdict::Fail(format!(
656	            "invest {} exit {}\n{}",
657	            role, invest.exit_code, invest.stderr
658	        ));
659	    }
660	
661	    if !assay.exists() {
662	        return rbtdre_Verdict::Fail(format!(
663	            "assay RBRA absent after invest-{}: {}",
664	            role,
665	            assay.display()
666	        ));
667	    }
668	
669	    let canonical = match rbtdrk_canonical_rbra(&root, role) {
670	        Ok(p) => p,
671	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical {} RBRA path: {}", role, e)),
672	    };
673	    if let Some(parent) = canonical.parent() {
674	        if let Err(e) = std::fs::create_dir_all(parent) {
675	            return rbtdre_Verdict::Fail(format!(
676	                "create {} RBRA dir {}: {}",
677	                role,
678	                parent.display(),
679	                e
680	            ));
681	        }
682	    }
683	    if let Err(e) = std::fs::copy(&assay, &canonical) {
684	        return rbtdre_Verdict::Fail(format!(
685	            "copy assay RBRA → {} canonical {}: {}",
686	            role,
687	            canonical.display(),
688	            e
689	        ));
690	    }
691	
692	    let probe_result = match rbtdri_invoke_imprint(ctx, RBTDRM_COLOPHON_ACCESS_PROBE, role, &[]) {
693	        Ok(r) => r,
694	        Err(e) => {
695	            return rbtdre_Verdict::Fail(format!("access-probe {} invocation: {}", role, e))
696	        }
697	    };
698	    let _ = std::fs::write(
699	        dir.join(format!("probe-{}-stdout.txt", role)),
700	        &probe_result.stdout,
701	    );
702	    let _ = std::fs::write(
703	        dir.join(format!("probe-{}-stderr.txt", role)),
704	        &probe_result.stderr,
705	    );
706	    if probe_result.exit_code != 0 {
707	        return rbtdre_Verdict::Fail(format!(
708	            "access-probe {} exit {}\n{}",
709	            role, probe_result.exit_code, probe_result.stderr
710	        ));
711	    }
712	
713	    rbtdre_Verdict::Pass
714	}
715	
716	// ── Section registry ─────────────────────────────────────────
717	
718	pub static RBTDRK_CASES_CANONICAL_ESTABLISH: &[rbtdre_Case] = &[
719	    case!(rbtdrk_depot_levy),
720	    case!(rbtdrk_governor_mantle),
721	    case!(rbtdrk_retriever_invest),
722	    case!(rbtdrk_director_invest),
723	];
724	
725	pub static RBTDRK_FIXTURE_CANONICAL_ESTABLISH: rbtdre_Fixture = rbtdre_Fixture {
726	    name: RBTDRM_FIXTURE_CANONICAL_ESTABLISH,
727	    disposition: rbtdre_Disposition::StateProgressing,
728	    setup: None,
729	    teardown: None,
730	    cases: RBTDRK_CASES_CANONICAL_ESTABLISH,
731	};
732

